class Solution:
    def countKthRoots(self, l: int, r: int, k: int) -> int:
        if k == 1:
            return max(0, r - l + 1)
        count = 0
        x = 0
        while True:
            p = x ** k
            if p > r:
                break
            if p >= l:
                count += 1
            x += 1
        return count

