class Solution:
    def countKthRoots(self, l: int, r: int, k: int) -> int:
        def leq(x, cap):
            if cap < 0:
                return False
            if x == 0:
                return True
            result = 1
            for _ in range(k):
                result *= x
                if result > cap:
                    return False
            return True

        lo, hi = 0, r
        x1 = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if leq(mid, r):
                x1 = mid
                lo = mid + 1
            else:
                hi = mid - 1

        lo, hi = 0, r
        x0 = r + 1
        while lo <= hi:
            mid = (lo + hi) // 2
            if leq(mid, l - 1):
                lo = mid + 1
            else:
                x0 = mid
                hi = mid - 1

        if x1 < 0 or x0 > x1:
            return 0
        return x1 - x0 + 1

