var countKthRoots = function(l, r, k) {
    function leq(x, cap) {
        if (cap < 0) return false;
        if (x === 0) return true;
        let result = 1;
        for (let i = 0; i < k; i++) {
            result *= x;
            if (result > cap) return false;
        }
        return true;
    }

    let lo = 0, hi = r, x1 = -1;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (leq(mid, r)) { x1 = mid; lo = mid + 1; }
        else hi = mid - 1;
    }

    lo = 0; hi = r;
    let x0 = r + 1;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (leq(mid, l - 1)) lo = mid + 1;
        else { x0 = mid; hi = mid - 1; }
    }

    if (x1 < 0 || x0 > x1) return 0;
    return x1 - x0 + 1;
};
